@st.cache_resource
def _make_vd_logo_b64() -> str:
    """Generate Viswa & Devji logo PNG as base64 (used when no VD_logo.png found)."""
    import base64 as _b64e
    sz = 400
    img  = Image.new("RGBA", (sz, sz), (0, 0, 0, 0))
    draw = ImageDraw.Draw(img)
    # Try loading system fonts; fall back gracefully
    try:
        _fpath = None
        for _fp in [
            "C:/Windows/Fonts/Georgia.ttf",
            "C:/Windows/Fonts/times.ttf",
            "/usr/share/fonts/truetype/dejavu/DejaVuSerifCondensed-Bold.ttf",
            "/System/Library/Fonts/Times.ttc",
        ]:
            if Path(_fp).exists():
                _fpath = _fp
                break
        fnt_big  = ImageFont.truetype(_fpath, 140) if _fpath else ImageFont.load_default()
        fnt_mid  = ImageFont.truetype(_fpath,  38) if _fpath else ImageFont.load_default()
        fnt_sm   = ImageFont.truetype(_fpath,  26) if _fpath else ImageFont.load_default()
    except Exception:
        fnt_big = fnt_mid = fnt_sm = ImageFont.load_default()
    W = WHITE = (255, 255, 255, 255)
    # "VD" monogram centred
    bb = draw.textbbox((0,0), "VD", font=fnt_big)
    tw, th = bb[2]-bb[0], bb[3]-bb[1]
    draw.text(((sz-tw)//2 - bb[0], 60 - bb[1]), "VD", font=fnt_big, fill=W)
    # "VISWA & DEVJI" centred
    bb2 = draw.textbbox((0,0), "VISWA & DEVJI", font=fnt_mid)
    tw2 = bb2[2]-bb2[0]
    draw.text(((sz-tw2)//2 - bb2[0], 230 - bb2[1]), "VISWA & DEVJI", font=fnt_mid, fill=W)
    # "Diamonds Since 1950" centred
    bb3 = draw.textbbox((0,0), "Diamonds Since 1950", font=fnt_sm)
    tw3 = bb3[2]-bb3[0]
    draw.text(((sz-tw3)//2 - bb3[0], 290 - bb3[1]), "Diamonds Since 1950", font=fnt_sm, fill=W)
    buf = io.BytesIO()
    img.save(buf, format="PNG")
    return "data:image/png;base64," + _b64e.b64encode(buf.getvalue()).decode()

def _get_vd_logo_uri() -> str:
    """Use VD_logo.png from model folder if present, else auto-generate."""
    import base64 as _b64e
    for _name in ["VD_logo.png", "VD_logo.jpg", "vd_logo.png", "vd_logo.jpg"]:
        _p = SCRIPT_DIR / _name
        if _p.exists():
            ext = _p.suffix.lower().replace(".", "")
            mime = "jpeg" if ext in ("jpg","jpeg") else "png"
            return f"data:image/{mime};base64," + _b64e.b64encode(_p.read_bytes()).decode()
    return _make_vd_logo_b64()

