def _co() -> dict:
    """Return current company config dict. Robust against empty/invalid values."""
    key = (st.session_state.get("company") or "wondr").strip()
    if key not in COMPANY_CFG:
        key = "wondr"
    cfg = COMPANY_CFG[key]
    if cfg["logo_uri"] is None:          # resolve VD logo once
        cfg["logo_uri"] = _get_vd_logo_uri()
    return cfg

# ── Text removal — strips watermarks/codes before bg removal ─────────────────
def clean_alpha_blobs(rgba_img: Image.Image) -> Image.Image:
    """After rembg, erase text/watermark blobs using a ZONE-based approach.

    Strategy:
      1. Find all coloured (gold/rose/gem) blobs → these are definitely jewelry.
      2. Build a bounding zone around those coloured blobs + 20% margin.
      3. Any blob that is OUTSIDE the zone AND looks text-coloured → drop.
      4. Anything inside the zone is always kept (diamonds, pearls, etc.).
    """
    try:
        import cv2
        arr   = np.array(rgba_img)
        alpha = arr[:, :, 3]
        rgb   = arr[:, :, :3].astype(np.float32)
        h, w  = alpha.shape

        _, binary = cv2.threshold(alpha, 10, 255, cv2.THRESH_BINARY)
        n, labels, stats, _ = cv2.connectedComponentsWithStats(
            binary, connectivity=8)

        if n <= 1:
            return rgba_img

        # ── Per-blob colour analysis ──────────────────────────────────────────
        blob_info = []
        for i in range(1, n):
            px         = rgb[labels == i]
            ch_max     = px.max(axis=1)
            ch_min     = px.min(axis=1)
            sat        = np.where(ch_max > 0, (ch_max - ch_min) / ch_max, 0).mean()
            brightness = px.mean()
            area       = int(stats[i, cv2.CC_STAT_AREA])
            blob_info.append((i, area, float(sat), float(brightness)))

        # ── Build jewelry zone from COLOURED blobs (sat >= 0.15) ─────────────
        jewel_blobs = [b for b in blob_info if b[2] >= 0.15]
        if not jewel_blobs:
            return rgba_img   # no clearly coloured blobs — leave untouched

        zone_x1 = min(stats[b[0], cv2.CC_STAT_LEFT] for b in jewel_blobs)
        zone_y1 = min(stats[b[0], cv2.CC_STAT_TOP]  for b in jewel_blobs)
        zone_x2 = max(stats[b[0], cv2.CC_STAT_LEFT] + stats[b[0], cv2.CC_STAT_WIDTH]  for b in jewel_blobs)
        zone_y2 = max(stats[b[0], cv2.CC_STAT_TOP]  + stats[b[0], cv2.CC_STAT_HEIGHT] for b in jewel_blobs)

        # Expand zone by 20% on each side to include non-coloured jewelry parts
        mx = int((zone_x2 - zone_x1) * 0.20)
        my = int((zone_y2 - zone_y1) * 0.20)
        zone_x1 = max(0, zone_x1 - mx)
        zone_y1 = max(0, zone_y1 - my)
        zone_x2 = min(w, zone_x2 + mx)
        zone_y2 = min(h, zone_y2 + my)

        # ── Filter blobs ──────────────────────────────────────────────────────
        clean_alpha = np.zeros_like(alpha)
        for i, area, sat, brightness in blob_info:
            bx1 = stats[i, cv2.CC_STAT_LEFT]
            bx2 = bx1 + stats[i, cv2.CC_STAT_WIDTH]
            by1 = stats[i, cv2.CC_STAT_TOP]
            by2 = by1 + stats[i, cv2.CC_STAT_HEIGHT]

            # Does this blob overlap the jewelry zone?
            in_zone = not (bx2 < zone_x1 or bx1 > zone_x2 or
                           by2 < zone_y1 or by1 > zone_y2)

            # Is the blob text-coloured? (dark OR very bright, low saturation)
            is_text = (sat < 0.22) and (brightness < 100 or brightness > 190)

            # Keep if inside zone OR not text-coloured; drop only if outside+text
            if in_zone or not is_text:
                clean_alpha[labels == i] = alpha[labels == i]

        result = rgba_img.copy()
        result.putalpha(Image.fromarray(clean_alpha))
        return result
    except Exception:
        return rgba_img

def suppress_support_objects(pil_img: Image.Image) -> Image.Image:
    """Pre-rembg: paint out large non-jewelry prop objects (Blu-Tack, foam, putty).

    Only activates on dark backgrounds (avg corner brightness < 70).
    Uses gold-adjacency to distinguish gems in settings from support props.
    """
    try:
        import cv2

        img  = np.array(pil_img.convert("RGB"))
        h, w = img.shape[:2]

        cs   = max(15, min(h, w) // 25)
        cnrs = np.vstack([
            img[:cs, :cs  ].reshape(-1, 3),
            img[:cs, -cs: ].reshape(-1, 3),
            img[-cs:, :cs ].reshape(-1, 3),
            img[-cs:, -cs:].reshape(-1, 3),
        ]).astype(np.float32)
        bg_color  = cnrs.mean(axis=0)
        bg_bright = float(bg_color.mean())

        if bg_bright > 70:
            return pil_img  # Light bg — skip

        hsv = cv2.cvtColor(img, cv2.COLOR_RGB2HSV)
        H   = hsv[:, :, 0].astype(np.float32)
        S   = hsv[:, :, 1].astype(np.float32) / 255.0
        V   = hsv[:, :, 2].astype(np.float32)

        warm = (
            ((H <= 28) | (H >= 168)) & (S > 0.22) & (V > 50)
        ).astype(np.uint8) * 255

        is_foreign = (H > 28) & (H < 168) & (S > 0.15) & (V > 35)
        candidate  = is_foreign.astype(np.uint8) * 255

        if candidate.sum() == 0:
            return pil_img

        n_comp, labels, stats, _ = cv2.connectedComponentsWithStats(
            candidate, connectivity=8)

        result   = img.copy()
        bg_px    = [int(bg_color[0]), int(bg_color[1]), int(bg_color[2])]
        MIN_AREA = max(int(h * w * 0.008), 400)
        k3       = cv2.getStructuringElement(cv2.MORPH_RECT, (3, 3))

        for ci in range(1, n_comp):
            area = int(stats[ci, cv2.CC_STAT_AREA])
            if area < MIN_AREA:
                continue

            blob    = (labels == ci)
            blob_u8 = blob.astype(np.uint8) * 255

            dilated  = cv2.dilate(blob_u8, k3)
            boundary = (dilated - blob_u8) > 0
            perim    = int(boundary.sum())
            if perim == 0:
                continue

            gold_adj = float((boundary & (warm > 0)).sum()) / perim
            if gold_adj > 0.35:
                continue

            blob_hue_std = float(H[blob].std())
            if blob_hue_std > 42:
                continue

            result[blob] = bg_px

        return Image.fromarray(result)

    except Exception:
        return pil_img


def suppress_fabric_dark_bg(pil_img: Image.Image) -> Image.Image:
    """Pre-rembg: paint large achromatic foreground blobs (tissue/cloth) BLACK.

    Strategy:
      1. Low threshold (35) captures the WHOLE fabric object including grey
         shadows and wrinkles — not just the bright centre.
      2. Connected components of those non-background pixels are found.
      3. Jewelry zone (coloured pixels + dilation) is excluded from candidates.
      4. Any remaining blob that is LARGE + mostly achromatic + average
         brightness > 70 = fabric → paint black so rembg ignores it entirely.
      Text characters are tiny (<< 0.5% of image) so they survive untouched.
    """
    try:
        import cv2
        img  = np.array(pil_img.convert("RGB"))
        h, w = img.shape[:2]

        # Only for dark backgrounds
        small = cv2.resize(img, (400, int(400 * h / w)), interpolation=cv2.INTER_AREA)
        sg    = cv2.cvtColor(small, cv2.COLOR_RGB2GRAY)
        if (sg < 25).sum() < sg.size * 0.25:
            return pil_img

        THUMB_W = 800
        THUMB_H = int(h * THUMB_W / w)
        thumb   = cv2.resize(img, (THUMB_W, THUMB_H), interpolation=cv2.INTER_AREA)
        tgray   = cv2.cvtColor(thumb, cv2.COLOR_RGB2GRAY)
        tr      = thumb[:, :, 0].astype(np.float32)
        tg_ch   = thumb[:, :, 1].astype(np.float32)
        tb      = thumb[:, :, 2].astype(np.float32)

        ch_max   = np.maximum(np.maximum(tr, tg_ch), tb)
        ch_min   = np.minimum(np.minimum(tr, tg_ch), tb)
        sat      = np.where(ch_max > 0, (ch_max - ch_min) / ch_max, 0)
        jewel_px = ((sat > 0.15) & (ch_max > 60)).astype(np.uint8) * 255

        # Generous dilation so the whole jewelry piece stays protected
        kern_j     = cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (71, 71))
        jewel_zone = cv2.dilate(jewel_px, kern_j)

        # Low threshold — captures tissue paper including its darker shadows
        _, fg_mask = cv2.threshold(tgray, 35, 255, cv2.THRESH_BINARY)

        # Exclude jewelry zone entirely
        candidate = fg_mask.copy()
        candidate[jewel_zone > 0] = 0

        # Connected components of the remaining non-background blobs
        num, labels, stats, _ = cv2.connectedComponentsWithStats(
            candidate, connectivity=8)
        min_area = int(THUMB_W * THUMB_H * 0.005)   # 0.5% ≈ fabric-object scale
        fabric   = np.zeros_like(candidate)
        for i in range(1, num):
            if stats[i, cv2.CC_STAT_AREA] < min_area:
                continue
            blob_gray = tgray[labels == i]
            blob_sat  = sat[labels == i]
            # Must be generally bright (>70 mean) and achromatic (mean sat < 0.20)
            if blob_gray.mean() > 70 and blob_sat.mean() < 0.20:
                fabric[labels == i] = 255

        if fabric.sum() == 0:
            return pil_img

        # Dilate to cover all wrinkle edges fully before scaling up
        kern_d  = cv2.getStructuringElement(cv2.MORPH_RECT, (13, 13))
        fabric  = cv2.dilate(fabric, kern_d, iterations=3)

        mask_full = cv2.resize(fabric, (w, h), interpolation=cv2.INTER_NEAREST)
        result    = img.copy()
        result[mask_full > 0] = [0, 0, 0]
        return Image.fromarray(result)
    except Exception:
        return pil_img


def suppress_text_dark_bg(pil_img: Image.Image) -> Image.Image:
    """For dark-background images: paint bright text pixels BLACK before rembg.
    All heavy OpenCV work is done on a small thumbnail (800px) for speed,
    then the mask is scaled back up and applied at full resolution."""
    try:
        import cv2
        img  = np.array(pil_img.convert("RGB"))
        h, w = img.shape[:2]

        # Only for dark background images (sample quickly at small scale)
        small = cv2.resize(img, (400, int(400 * h / w)),
                           interpolation=cv2.INTER_AREA)
        sg    = cv2.cvtColor(small, cv2.COLOR_RGB2GRAY)
        if (sg < 25).sum() < sg.size * 0.25:
            return pil_img   # not a dark bg image

        # ── Work at thumb scale (800px wide) for speed ────────────────────────
        THUMB_W = 800
        THUMB_H = int(h * THUMB_W / w)
        thumb   = cv2.resize(img, (THUMB_W, THUMB_H), interpolation=cv2.INTER_AREA)
        tgray   = cv2.cvtColor(thumb, cv2.COLOR_RGB2GRAY)
        tr      = thumb[:, :, 0].astype(np.float32)
        tg_ch   = thumb[:, :, 1].astype(np.float32)
        tb      = thumb[:, :, 2].astype(np.float32)

        ch_max   = np.maximum(np.maximum(tr, tg_ch), tb)
        ch_min   = np.minimum(np.minimum(tr, tg_ch), tb)
        sat      = np.where(ch_max > 0, (ch_max - ch_min) / ch_max, 0)
        jewel_px = ((sat > 0.15) & (ch_max > 60)).astype(np.uint8) * 255

        # Fixed small kernel (fast) — 60px dilation at 800px width ≈ 7.5%
        kern_j     = cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (61, 61))
        jewel_zone = cv2.dilate(jewel_px, kern_j)

        # Lower threshold to 140 to catch anti-aliased edges of larger text
        bright  = (tgray > 140).astype(np.uint8) * 255
        outside = cv2.bitwise_and(bright, cv2.bitwise_not(jewel_zone))

        # Remove tiny stray specks (noise), keep real text clusters
        kern_open = cv2.getStructuringElement(cv2.MORPH_RECT, (3, 3))
        outside   = cv2.morphologyEx(outside, cv2.MORPH_OPEN, kern_open)

        if outside.sum() == 0:
            return pil_img

        # Dilate mask to fully cover character edges before scaling up
        kern_d  = cv2.getStructuringElement(cv2.MORPH_RECT, (7, 7))
        outside = cv2.dilate(outside, kern_d, iterations=2)

        # ── Scale mask back to full resolution and apply ──────────────────────
        mask_full = cv2.resize(outside, (w, h), interpolation=cv2.INTER_NEAREST)
        result    = img.copy()
        result[mask_full > 0] = [0, 0, 0]
        return Image.fromarray(result)
    except Exception:
        return pil_img

def suppress_text_light_bg(pil_img: Image.Image) -> Image.Image:
    """For white-background images: paint dark text pixels WHITE before rembg.
    Mirrors suppress_text_dark_bg — same zone-protection logic, inverted colours."""
    try:
        import cv2
        img  = np.array(pil_img.convert("RGB"))
        h, w = img.shape[:2]

        # Only for light background images (>25% very bright pixels)
        small = cv2.resize(img, (400, int(400 * h / w)), interpolation=cv2.INTER_AREA)
        sg    = cv2.cvtColor(small, cv2.COLOR_RGB2GRAY)
        if (sg > 240).sum() < sg.size * 0.25:
            return pil_img   # not a light bg image

        # ── Work at 800px thumbnail for speed ────────────────────────────────
        THUMB_W = 800
        THUMB_H = int(h * THUMB_W / w)
        thumb   = cv2.resize(img, (THUMB_W, THUMB_H), interpolation=cv2.INTER_AREA)
        tgray   = cv2.cvtColor(thumb, cv2.COLOR_RGB2GRAY)
        tr      = thumb[:, :, 0].astype(np.float32)
        tg_ch   = thumb[:, :, 1].astype(np.float32)
        tb      = thumb[:, :, 2].astype(np.float32)

        # Jewelry zone = coloured pixels (gold, rose gold, gems)
        ch_max   = np.maximum(np.maximum(tr, tg_ch), tb)
        ch_min   = np.minimum(np.minimum(tr, tg_ch), tb)
        sat      = np.where(ch_max > 0, (ch_max - ch_min) / ch_max, 0)
        jewel_px = ((sat > 0.15) & (ch_max > 60)).astype(np.uint8) * 255

        # Dilate to create protective bubble around jewelry
        kern_j     = cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (61, 61))
        jewel_zone = cv2.dilate(jewel_px, kern_j)

        # Dark pixels outside jewelry zone = black text on white bg
        dark    = (tgray < 140).astype(np.uint8) * 255
        outside = cv2.bitwise_and(dark, cv2.bitwise_not(jewel_zone))

        # Remove noise, keep real text clusters
        kern_open = cv2.getStructuringElement(cv2.MORPH_RECT, (3, 3))
        outside   = cv2.morphologyEx(outside, cv2.MORPH_OPEN, kern_open)

        if outside.sum() == 0:
            return pil_img

        # Dilate mask to fully cover character edges
        kern_d  = cv2.getStructuringElement(cv2.MORPH_RECT, (7, 7))
        outside = cv2.dilate(outside, kern_d, iterations=2)

        # Scale mask back to full resolution and paint text WHITE
        mask_full = cv2.resize(outside, (w, h), interpolation=cv2.INTER_NEAREST)
        result    = img.copy()
        result[mask_full > 0] = [255, 255, 255]
        return Image.fromarray(result)
    except Exception:
        return pil_img

# ── Background removal — full original resolution preserved ───────────────────
def clean_jewelry_zone(rgba_img: Image.Image) -> Image.Image:
    """After rembg: keep ONLY pixels inside the jewellery zone, erase everything else.

    Works at a fixed 1000-px thumbnail so the dilation kernel is always small
    and fast, then scales the binary mask back to full resolution.
    """
    try:
        import cv2
        arr   = np.array(rgba_img)
        h, w  = arr.shape[:2]

        # ── work at reduced resolution to keep dilation kernel small ──────────
        WORK_W = 1000
        WORK_H = int(h * WORK_W / w)
        small_rgba = cv2.resize(arr, (WORK_W, WORK_H), interpolation=cv2.INTER_AREA)

        alpha_s  = small_rgba[:, :, 3]
        rgb_s    = small_rgba[:, :, :3].astype(np.float32)
        opaque_s = (alpha_s > 128)

        r, g, b  = rgb_s[:,:,0], rgb_s[:,:,1], rgb_s[:,:,2]
        ch_max   = np.maximum(np.maximum(r, g), b)
        ch_min   = np.minimum(np.minimum(r, g), b)
        sat      = np.where(ch_max > 0, (ch_max - ch_min) / ch_max, 0)

        # Jewellery core: coloured + opaque
        jewel_px = ((sat > 0.12) & (ch_max > 40) & opaque_s).astype(np.uint8) * 255

        if jewel_px.sum() == 0:
            return rgba_img   # no coloured pixels found — leave untouched

        # Dilation size = 60% of jewellery span in the thumbnail (always ≤ ~600 px)
        ys_j, xs_j = np.where(jewel_px > 0)
        span = max(int(xs_j.max() - xs_j.min()),
                   int(ys_j.max() - ys_j.min()), 50)
        ks   = max(int(span * 0.60), 31)
        if ks % 2 == 0: ks += 1
        kern = cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (ks, ks))
        zone_small = cv2.dilate(jewel_px, kern)

        # Scale mask back to full resolution
        zone_full = cv2.resize(zone_small, (w, h), interpolation=cv2.INTER_NEAREST)

        # Zero alpha outside zone
        result = arr.copy()
        result[zone_full == 0, 3] = 0
        return Image.fromarray(result)
    except Exception:
        return rgba_img


def erase_residual_background(rgba_img: Image.Image, orig_pil: Image.Image) -> Image.Image:
    """Two-pass removal of dark background residue left by rembg inside jewelry curves.

    PASS A — Original-colour match (most reliable):
      For each opaque pixel in the rembg output, look up its colour in the
      ORIGINAL image.  If that colour was within 50 intensity units of the
      detected background colour AND the pixel is dark AND achromatic, it is a
      background pixel rembg should have removed.  Connected blobs of such pixels
      that touch the already-transparent exterior are erased entirely.

    PASS B — Output-image dark-blob scan (catches semi-transparent residue):
      At reduced resolution, scan connected opaque blobs whose mean colour in the
      OUTPUT image is dark and achromatic.  Blobs with ≥ 10 % boundary exposure
      to transparent pixels are erased.  Blobs larger than 4 % of the canvas are
      skipped (protects genuine dark gemstones).

    Both passes only activate when the original image had a dark (avg < 60),
    achromatic (saturation < 0.30) background.
    """
    try:
        import cv2

        # ── Detect background colour from original image corners ──────────────
        orig_arr = np.array(orig_pil.convert("RGB")).astype(np.float32)
        h, w     = orig_arr.shape[:2]
        arr      = np.array(rgba_img)
        alpha    = arr[:, :, 3]

        cs   = max(20, min(h, w) // 20)
        cnrs = np.vstack([
            orig_arr[:cs, :cs  ].reshape(-1, 3),
            orig_arr[:cs, -cs: ].reshape(-1, 3),
            orig_arr[-cs:, :cs ].reshape(-1, 3),
            orig_arr[-cs:, -cs:].reshape(-1, 3),
        ])
        bg_rgb    = cnrs.mean(axis=0)
        bg_bright = float(bg_rgb.mean())
        bg_ch_max = cnrs.max(axis=1)
        bg_ch_min = cnrs.min(axis=1)
        bg_sat    = float(np.where(bg_ch_max > 0,
                                   (bg_ch_max - bg_ch_min) / bg_ch_max, 0).mean())

        if bg_bright > 60 or bg_sat > 0.30:
            return rgba_img          # not a dark achromatic bg → skip both passes

        erase_mask = np.zeros((h, w), dtype=np.uint8)

        # ════════════════════════════════════════════════════════════════════
        # PASS A: compare every opaque pixel against original background colour
        # ════════════════════════════════════════════════════════════════════
        diff        = np.abs(orig_arr - bg_rgb).max(axis=2)      # max-channel dist
        orig_bright = orig_arr.mean(axis=2)
        orig_cmax   = orig_arr.max(axis=2)
        orig_cmin   = orig_arr.min(axis=2)
        orig_sat    = np.where(orig_cmax > 0,
                               (orig_cmax - orig_cmin) / orig_cmax, 0)

        # Candidate pixels: opaque in output, but originally looked like bg
        bg_match    = (alpha > 15) & (diff < 50) & \
                      (orig_bright < 85) & (orig_sat < 0.28)

        if bg_match.any():
            # Use a small 3-px dilation of transparent so blobs just touching the
            # boundary are caught, but we don't reach 19 px deep (which was too
            # aggressive and erased residue inside concave jewelry curves).
            trans_u8    = (alpha == 0).astype(np.uint8)
            k3          = np.ones((3, 3), np.uint8)
            adj_trans   = cv2.dilate(trans_u8, k3).astype(bool)

            # Connected blobs of bg-matching pixels that touch the exterior → erase
            _, lbl_a, _, _ = cv2.connectedComponentsWithStats(
                bg_match.astype(np.uint8) * 255, connectivity=8)
            n_a = int(lbl_a.max())
            for ci in range(1, n_a + 1):
                blob = lbl_a == ci
                if (blob & adj_trans).any():
                    erase_mask[blob] = 255

        # ════════════════════════════════════════════════════════════════════
        # PASS B: scan dark blobs in the OUTPUT image at reduced resolution
        # ════════════════════════════════════════════════════════════════════
        WORK = 1000
        sf   = min(WORK / w, WORK / h)
        ww   = max(1, int(w * sf))
        wh   = max(1, int(h * sf))
        sm   = cv2.resize(arr, (ww, wh), interpolation=cv2.INTER_AREA)
        s_a  = sm[:, :, 3]
        s_rgb = sm[:, :, :3].astype(np.float32)

        _, bin_b = cv2.threshold(s_a, 15, 255, cv2.THRESH_BINARY)
        n_b, lbl_b, stats_b, _ = cv2.connectedComponentsWithStats(
            bin_b, connectivity=8)

        k1       = cv2.getStructuringElement(cv2.MORPH_RECT, (3, 3))
        b_erase  = np.zeros((wh, ww), dtype=np.uint8)

        for ci in range(1, n_b):
            area = int(stats_b[ci, cv2.CC_STAT_AREA])
            if area < 8 or area > ww * wh * 0.04:
                continue          # noise or too large (genuine feature)

            px        = s_rgb[lbl_b == ci]
            ch_max    = px.max(axis=1)
            ch_min    = px.min(axis=1)
            avg_b     = float(px.mean())
            avg_s     = float(np.where(ch_max > 0,
                                       (ch_max - ch_min) / ch_max, 0).mean())

            if avg_b >= 70 or avg_s >= 0.28:
                continue          # not dark/achromatic enough

            blob_mask = (lbl_b == ci).astype(np.uint8)
            dilated   = cv2.dilate(blob_mask, k1)
            boundary  = (dilated - blob_mask).astype(bool)
            b_total   = int(boundary.sum())
            if b_total == 0:
                continue

            exposed = float(((boundary) & (s_a == 0)).sum()) / b_total
            if exposed >= 0.10:                         # lowered from 0.15 → more aggressive
                b_erase[lbl_b == ci] = 255

        if b_erase.any():
            b_full = cv2.resize(b_erase, (w, h), interpolation=cv2.INTER_NEAREST)
            erase_mask = np.clip(erase_mask.astype(np.uint16) + b_full, 0, 255).astype(np.uint8)

        # ── Apply combined erase mask ─────────────────────────────────────────
        if not erase_mask.any():
            return rgba_img

        result = arr.copy()
        result[erase_mask > 0, 3] = 0
        return Image.fromarray(result)

    except Exception:
        return rgba_img


def restore_bright_pixels(rgba_img: Image.Image) -> Image.Image:
    """Prevent diamonds / white gems from appearing grey on dark output backgrounds.

    rembg assigns partial alpha to bright gem facets and sparkle highlights.
    When the final canvas uses a dark background this partial transparency causes
    those pixels to composite as dark-grey instead of bright white.

    Strategy:
      1. Find the 'interior' of the jewellery (erode opaque mask slightly so the
         outer anti-aliased edge is left untouched).
      2. Within that interior, any pixel whose alpha is 40-239 AND whose RGB
         brightness is > 140 is a gem/diamond highlight → restore to alpha = 255.
      3. Very bright near-edge pixels (alpha > 200, brightness > 180) are also
         boosted to prevent subtle graying at gem boundaries.
    """
    try:
        import cv2
        arr      = np.array(rgba_img)
        alpha    = arr[:, :, 3].astype(np.float32)
        rgb      = arr[:, :, :3].astype(np.float32)
        brightness = rgb.mean(axis=2)

        # Interior mask: erode the fully-opaque region to protect outer AA edge
        opaque_core = (alpha > 200).astype(np.uint8) * 255
        kern7       = cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (7, 7))
        interior    = cv2.erode(opaque_core, kern7) > 0

        result = arr.copy()

        # Interior semi-transparent bright pixels → full opacity (diamonds, gems)
        fix_interior = (alpha > 40) & (alpha < 240) & (brightness > 140) & interior
        result[fix_interior, 3] = 255

        # Near-edge bright pixels (likely gem facets at jewelry boundary)
        fix_edge = (alpha > 200) & (brightness > 180) & (~interior)
        result[fix_edge, 3] = 255

        return Image.fromarray(result)

    except Exception:
        return rgba_img


def erase_teal_prop_postprocess(rgba_img: Image.Image) -> Image.Image:
    """Post-rembg: erase any remaining teal/blue-green prop pixels (Blu-Tack etc).

    After rembg the background is already transparent.  Any surviving teal blob
    that sits BELOW the jewelry's warm-gold pixels is a prop — not a gem.
    We set those pixels to fully transparent.

    This is safer than pre-processing because rembg has already separated the
    jewelry outline cleanly, so we only look at pixels that were explicitly kept.
    """
    try:
        import cv2
        arr  = np.array(rgba_img.convert("RGBA"))
        h, w = arr.shape[:2]
        alpha = arr[:, :, 3]
        opaque = alpha > 30                          # pixels rembg decided to keep

        if not opaque.any():
            return rgba_img

        rgb = arr[:, :, :3].copy()
        hsv = cv2.cvtColor(rgb, cv2.COLOR_RGB2HSV)
        H   = hsv[:, :, 0].astype(np.float32)
        S   = hsv[:, :, 1].astype(np.float32) / 255.0
        V   = hsv[:, :, 2].astype(np.float32)

        # Warm gold pixels among the kept pixels
        warm = ((H <= 30) | (H >= 165)) & (S > 0.18) & (V > 40) & opaque
        ys_warm = np.where(warm)[0]
        if len(ys_warm) == 0:
            return rgba_img                          # no gold → silver/platinum → skip

        y_gold_bottom = int(ys_warm.max())
        y_gold_top    = int(ys_warm.min())
        ring_h        = max(y_gold_bottom - y_gold_top, 1)
        overlap_px    = max(int(ring_h * 0.40), 20)
        erase_from_y  = max(0, y_gold_bottom - overlap_px)

        # Teal / blue-green opaque pixels below the gold zone
        teal_prop = np.zeros((h, w), dtype=bool)
        teal_prop[erase_from_y:, :] = (
            opaque[erase_from_y:, :]           &
            (H[erase_from_y:, :] >  50)        &
            (H[erase_from_y:, :] < 135)        &
            (S[erase_from_y:, :] > 0.18)       &
            (~warm[erase_from_y:, :])
        )

        if not teal_prop.any():
            return rgba_img

        result = arr.copy()
        result[teal_prop, 3] = 0                     # make transparent
        return Image.fromarray(result)

    except Exception:
        return rgba_img


def defringe_dark_edges(rgba_img: Image.Image) -> Image.Image:
    """Remove dark fringe pixels at alpha boundaries.

    rembg leaves semi-transparent dark pixels at cut edges. On black backgrounds
    these are invisible, but on white they show as ugly black outlines around
    ring stands / props. Fix: zero-out pixels that are BOTH semi-transparent
    (alpha 1-149) AND very dark (luminance < 50).
    Fully-opaque dark pixels such as gemstones (alpha >= 150) are never touched.
    """
    arr  = np.array(rgba_img.convert("RGBA"))
    a    = arr[:, :, 3]
    r, g, b = arr[:, :, 0].astype(np.int32), arr[:, :, 1].astype(np.int32), arr[:, :, 2].astype(np.int32)
    lum  = (r * 299 + g * 587 + b * 114) // 1000
    # Tightened thresholds: alpha < 150 (not 200) and lum < 50 (not 60)
    # so dark stone edges with higher alpha or slightly more colour are preserved
    fringe = (a > 0) & (a < 150) & (lum < 50)
    arr[fringe, 3] = 0
    return Image.fromarray(arr)


def clear_enclosed_dark_gaps(rgba_img: Image.Image) -> Image.Image:
    """Make transparent enclosed dark shadow regions inside the jewelry silhouette.

    Core idea: a "gap" is a dark opaque region that has NO path to the image
    border through transparent pixels. We identify the EXTERIOR background
    (transparent pixels connected to the image border) and dilate it by 1px.
    Any dark component whose pixels are NOT adjacent to that exterior zone is
    truly enclosed in the jewelry and should be cleared.

    This correctly handles both white and dark input backgrounds, and avoids
    accidentally treating interior transparent holes (already cleared by rembg)
    as exterior background.
    """
    try:
        arr   = np.array(rgba_img.convert("RGBA"))
        alpha = arr[:, :, 3]
        r = arr[:, :, 0].astype(np.int32)
        g = arr[:, :, 1].astype(np.int32)
        b = arr[:, :, 2].astype(np.int32)
        lum   = (r * 299 + g * 587 + b * 114) // 1000
        h, w  = alpha.shape
        total = h * w

        opaque_dark = ((alpha > 128) & (lum < 60)).astype(np.uint8)
        if not opaque_dark.any():
            return rgba_img

        kern = np.ones((3, 3), np.uint8)

        # ── Step 1: find transparent components that touch the image border ──
        # These are the EXTERIOR background. Interior transparent holes
        # (rembg-cleared regions already inside the jewelry) are excluded.
        trans_mask = (alpha == 0).astype(np.uint8)
        num_t, labels_t, stats_t, _ = cv2.connectedComponentsWithStats(
            trans_mask, connectivity=8
        )
        exterior_ids = []
        for t_lab in range(1, num_t):
            x0t = int(stats_t[t_lab, cv2.CC_STAT_LEFT])
            y0t = int(stats_t[t_lab, cv2.CC_STAT_TOP])
            x1t = x0t + int(stats_t[t_lab, cv2.CC_STAT_WIDTH])  - 1
            y1t = y0t + int(stats_t[t_lab, cv2.CC_STAT_HEIGHT]) - 1
            if x0t <= 0 or y0t <= 0 or x1t >= w - 1 or y1t >= h - 1:
                exterior_ids.append(t_lab)

        if not exterior_ids:
            return rgba_img          # no exterior bg found — nothing to do

        exterior_mask = np.isin(labels_t, exterior_ids).astype(np.uint8)

        # ── Step 2: dilate exterior mask by 1px — marks "adjacent to exterior" ──
        adj_exterior = cv2.dilate(exterior_mask, kern, iterations=1).astype(bool)

        # ── Step 3: scan dark components ─────────────────────────────────────
        num_labels, labels, stats, _ = cv2.connectedComponentsWithStats(
            opaque_dark, connectivity=8
        )

        result = arr.copy()
        for lab in range(1, num_labels):
            area = int(stats[lab, cv2.CC_STAT_AREA])
            if area > total * 0.015:        # large → dark stone cluster, keep
                continue

            x0 = int(stats[lab, cv2.CC_STAT_LEFT])
            y0 = int(stats[lab, cv2.CC_STAT_TOP])
            x1 = x0 + int(stats[lab, cv2.CC_STAT_WIDTH])
            y1 = y0 + int(stats[lab, cv2.CC_STAT_HEIGHT])

            comp_crop = (labels[y0:y1, x0:x1] == lab)
            adj_crop  = adj_exterior[y0:y1, x0:x1]

            # If ≥ 40% of this component's pixels border the EXTERIOR background
            # it is an outer-edge silhouette fragment — leave it alone.
            # If < 40% → it is enclosed inside the jewelry → clear it.
            n_adj = int(adj_crop[comp_crop].sum())
            if n_adj / max(area, 1) >= 0.40:
                continue

            # Skip textured — faceted dark gems shimmer; hook shadows are flat
            comp_lum = lum[y0:y1, x0:x1][comp_crop]
            if comp_lum.std() > 12:
                continue

            # Enclosed flat dark gap → transparent
            result[labels == lab, 3] = 0

        return Image.fromarray(result)

    except Exception:
        return rgba_img


def refine_dark_bg_alpha(rgba_img: Image.Image, orig_pil: Image.Image) -> Image.Image:
    """Extra alpha-refinement pass dedicated to dark-background input images.

    rembg's ISNet mask is significantly noisier on dark backgrounds because the
    contrast between jewelry and background is low (both dark). Problems:
      • Dark semi-transparent fringe pixels remain along the silhouette edge
      • Isolated 1–2 px noise specks scattered across the alpha mask
      • Slightly lifted alpha (150–220) on background pixels near curves

    This pass fixes all three without touching fully-opaque pixels (alpha=255),
    so dark gemstones and metal surfaces are never affected.

    Steps:
      1. Detect dark background from image corners (lum < 65, sat < 0.30).
      2. Find the "near-edge" zone (5px dilation of transparent region).
      3. Remove dark semi-transparent pixels in that zone:
         alpha < 240 AND lum < 90 AND in near-edge zone → transparent.
      4. Morphological opening on the binary alpha mask (3px ellipse, 1 pass)
         to remove 1–2 px noise specs and thin jagged protrusions.
    """
    try:
        # ── 1. Detect dark background ────────────────────────────────────────
        orig_arr = np.array(orig_pil.convert("RGB")).astype(np.float32)
        oh, ow   = orig_arr.shape[:2]
        cs       = max(15, min(oh, ow) // 20)
        corners  = np.vstack([
            orig_arr[:cs, :cs].reshape(-1, 3),
            orig_arr[:cs, -cs:].reshape(-1, 3),
            orig_arr[-cs:, :cs].reshape(-1, 3),
            orig_arr[-cs:, -cs:].reshape(-1, 3),
        ])
        bg_lum = float((corners[:, 0] * 0.299 +
                        corners[:, 1] * 0.587 +
                        corners[:, 2] * 0.114).mean())
        ch_max = corners.max(axis=1)
        ch_min = corners.min(axis=1)
        bg_sat = float(np.where(ch_max > 0,
                                (ch_max - ch_min) / ch_max, 0).mean())
        if bg_lum > 65 or bg_sat > 0.30:
            return rgba_img          # not a dark achromatic bg — skip

        # ── 2. Prepare arrays ────────────────────────────────────────────────
        arr   = np.array(rgba_img.convert("RGBA"))
        alpha = arr[:, :, 3]
        r = arr[:, :, 0].astype(np.int32)
        g = arr[:, :, 1].astype(np.int32)
        b = arr[:, :, 2].astype(np.int32)
        lum   = (r * 299 + g * 587 + b * 114) // 1000

        kern5 = np.ones((5, 5), np.uint8)

        # ── 3. Remove dark semi-transparent fringe near the alpha boundary ───
        # Expand the transparent region by 5 px to define the "edge zone"
        near_edge = cv2.dilate((alpha == 0).astype(np.uint8),
                               kern5, iterations=1).astype(bool)
        dark_fringe = (alpha > 0) & (alpha < 240) & (lum < 90) & near_edge
        arr[dark_fringe, 3] = 0

        # ── 4. Alpha mask morphological opening — remove noise specks ────────
        # Erode then dilate (= opening): removes tiny isolated transparent and
        # opaque specks without shrinking the main jewelry silhouette.
        kern_e = cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (3, 3))
        binary = (arr[:, :, 3] > 128).astype(np.uint8)
        opened = cv2.morphologyEx(binary, cv2.MORPH_OPEN, kern_e, iterations=1)
        # Only clear the pixels that opening removed AND that are near transparent
        noise_specks = (binary == 1) & (opened == 0)
        arr[noise_specks, 3] = 0

        return Image.fromarray(arr)

    except Exception:
        return rgba_img


def sharpen_alpha_edges(rgba_img: Image.Image, strength: int = 0) -> Image.Image:
    """Harden the feathered alpha edge produced by rembg.

    strength = 0  → no change (pass-through)
    strength = 1  → soft sharpening  (threshold ~40, push-up ~210)
    strength = 2  → medium           (threshold ~60, push-up ~200)
    strength = 3  → hard cutout      (threshold ~80, push-up ~190)

    Algorithm:
      • Pixels with alpha < low_thresh  → fully transparent (0)
      • Pixels with alpha > high_thresh → fully opaque (255)
      • Pixels in between → steepened S-curve so the transition zone narrows
    This removes the feathering/haze in the corners while keeping a thin
    natural anti-alias strip at the jewellery silhouette.
    """
    if strength == 0:
        return rgba_img

    # Thresholds per strength level
    params = {
        1: (30,  220),   # soft — only clips very faint ghost pixels
        2: (55,  205),   # medium
        3: (80,  190),   # hard cutout
    }
    low, high = params.get(strength, (55, 205))

    arr = np.array(rgba_img.convert("RGBA"), dtype=np.uint8)
    a   = arr[:, :, 3].astype(np.float32)

    # Fully transparent zone
    a[a < low]  = 0
    # Fully opaque zone
    a[a > high] = 255
    # Transition zone: linear remap low→0, high→255 (steeper curve)
    mid = (a >= low) & (a <= high)
    a[mid] = np.clip((a[mid] - low) / max(high - low, 1) * 255, 0, 255)

    arr[:, :, 3] = a.astype(np.uint8)
    return Image.fromarray(arr)


def suppress_paper_roll(pil_img: Image.Image) -> Image.Image:
    """Pre-rembg: detect and erase cylindrical paper/foam props used to hold bangles.

    The prop is a white/cream roll (high V, low S) that appears as a large
    elongated bright region inside or around the bangle. Painting it with the
    background colour before rembg ensures it is treated as background and removed.
    Only runs on dark-background images where the white roll stands out clearly.
    """
    try:
        import cv2
        img  = np.array(pil_img.convert("RGB"))
        h, w = img.shape[:2]

        cs   = max(10, min(h, w) // 25)
        cnrs = np.vstack([
            img[:cs, :cs].reshape(-1, 3),
            img[:cs, -cs:].reshape(-1, 3),
            img[-cs:, :cs].reshape(-1, 3),
            img[-cs:, -cs:].reshape(-1, 3),
        ]).astype(np.float32)
        bg_bright = float(cnrs.mean())
        if bg_bright > 80:
            return pil_img   # light background — prop blends in, skip

        bg_px = cnrs.mean(axis=0).astype(int).tolist()

        hsv = cv2.cvtColor(img, cv2.COLOR_RGB2HSV)
        S   = hsv[:, :, 1].astype(float) / 255.0
        V   = hsv[:, :, 2].astype(float)

        # White/cream paper roll: bright (V > 175) and nearly achromatic (S < 0.28)
        paper_mask = ((V > 175) & (S < 0.28)).astype(np.uint8)

        # Remove tiny specs — only consider substantial connected regions
        kern5 = cv2.getStructuringElement(cv2.MORPH_ELLIPSE, (5, 5))
        paper_mask = cv2.morphologyEx(paper_mask, cv2.MORPH_OPEN, kern5)

        n_comp, labels, stats, _ = cv2.connectedComponentsWithStats(paper_mask, connectivity=8)
        min_area = h * w * 0.015   # at least 1.5% of image area

        result = img.copy()
        for ci in range(1, n_comp):
            area = int(stats[ci, cv2.CC_STAT_AREA])
            if area < min_area:
                continue
            bw = int(stats[ci, cv2.CC_STAT_WIDTH])
            bh = int(stats[ci, cv2.CC_STAT_HEIGHT])
            aspect = max(bw, bh) / max(min(bw, bh), 1)
            # Must be elongated like a cylinder (aspect ratio ≥ 2.5)
            if aspect < 2.5:
                continue
            blob = (labels == ci)
            result[blob] = bg_px

        return Image.fromarray(result)

    except Exception:
        return pil_img


def restore_enclosed_dark_stones(rgba_result: Image.Image,
                                 orig_pil: Image.Image) -> Image.Image:
    """Post-rembg: recover dark stones/gems mistaken for black background.

    On dark-background images, rembg cannot distinguish black/dark stones from
    the black background — they both disappear. This function finds transparent
    regions that are ENCLOSED by opaque jewelry (not connected to the image
    border = not true background) and checks whether those pixels showed
    texture/variation in the original (stones have facet shimmer; pure flat
    background does not). Such regions are restored to full opacity.
    """
    try:
        import cv2
        arr      = np.array(rgba_result.copy())
        orig_arr = np.array(orig_pil.convert("RGB"))
        h, w     = arr.shape[:2]

        # Only run on dark-background originals
        cs   = max(10, min(h, w) // 25)
        cnrs = np.vstack([
            orig_arr[:cs, :cs].reshape(-1, 3),
            orig_arr[:cs, -cs:].reshape(-1, 3),
            orig_arr[-cs:, :cs].reshape(-1, 3),
            orig_arr[-cs:, -cs:].reshape(-1, 3),
        ]).astype(np.float32)
        bg_lum = float((cnrs[:, 0] * 0.299 + cnrs[:, 1] * 0.587 + cnrs[:, 2] * 0.114).mean())
        if bg_lum > 70:
            return rgba_result   # light background — not needed

        alpha     = arr[:, :, 3]
        transp_u8 = ((alpha < 10).astype(np.uint8)) * 255

        # Flood-fill from all 4 borders to label background-connected transparent pixels
        bg_flood  = transp_u8.copy()
        flood_buf = np.zeros((h + 2, w + 2), np.uint8)
        for x in range(w):
            if bg_flood[0, x] == 255:
                cv2.floodFill(bg_flood, flood_buf, (x, 0),   128)
            if bg_flood[h-1, x] == 255:
                cv2.floodFill(bg_flood, flood_buf, (x, h-1), 128)
        for y in range(h):
            if bg_flood[y, 0] == 255:
                cv2.floodFill(bg_flood, flood_buf, (0,   y), 128)
            if bg_flood[y, w-1] == 255:
                cv2.floodFill(bg_flood, flood_buf, (w-1, y), 128)

        # Interior transparent = transparent but NOT reached from border
        interior = (transp_u8 == 255) & (bg_flood != 128)
        if not interior.any():
            return rgba_result

        num_labels, labels = cv2.connectedComponents(interior.astype(np.uint8))

        result = arr.copy()
        for lbl in range(1, num_labels):
            region = labels == lbl
            if not region.any():
                continue

            # Texture check: dark stones have facet shimmer → std > pure flat black
            r_v = orig_arr[:, :, 0][region].astype(float)
            g_v = orig_arr[:, :, 1][region].astype(float)
            b_v = orig_arr[:, :, 2][region].astype(float)
            # Per-pixel luminance std across the region
            lum_v   = r_v * 0.299 + g_v * 0.587 + b_v * 0.114
            lum_std = float(lum_v.std())
            med_lum = float(np.median(lum_v))

            # Dark stone criteria:
            #   • region is dark in the original (med_lum < 80)
            #   • region has texture / facet variation (std > 7) — not flat background
            #     (raised from 4: JPEG noise on black bg can give std 3-6, causing
            #      background pixels to be incorrectly restored as "stones")
            if med_lum < 80 and lum_std > 7:
                result[region, 0] = orig_arr[region, 0]
                result[region, 1] = orig_arr[region, 1]
                result[region, 2] = orig_arr[region, 2]
                result[region, 3] = 255

        return Image.fromarray(result)

    except Exception:
        return rgba_result


def remove_bg(pil_img: Image.Image) -> Image.Image:
    """Pre-suppress fabric + text, remove background, then strip any residue."""
    orig    = pil_img                                    # keep original for colour analysis
    cleaned = suppress_paper_roll(pil_img)               # white/cream cylindrical prop → bg colour
    cleaned = suppress_support_objects(cleaned)          # Blu-Tack / foam / putty → black
    cleaned = suppress_fabric_dark_bg(cleaned)           # large white fabric blobs → black
    cleaned = suppress_text_dark_bg(cleaned)             # bright text on black bg → black
    cleaned = suppress_text_light_bg(cleaned)            # dark text on white bg → white
    result  = remove(cleaned, session=_sess)
    if not isinstance(result, Image.Image):
        result = Image.open(io.BytesIO(result))
    result = result.convert("RGBA")
    result = clean_jewelry_zone(result)                  # erase pixels outside jewel zone
    result = erase_residual_background(result, orig)     # 2-pass: remove dark bg in curves
    result = restore_bright_pixels(result)               # fix diamonds/gems going grey on dark bg
    result = restore_enclosed_dark_stones(result, orig)  # recover dark stones eaten by rembg on dark bg
    result = erase_teal_prop_postprocess(result)         # post: erase surviving Blu-Tack / teal props
    result = defringe_dark_edges(result)                 # remove dark halo on light backgrounds
    result = refine_dark_bg_alpha(result, orig)          # dark-bg only: strip fringe + noise specks
    result = clear_enclosed_dark_gaps(result)            # clear shadow inside hook/clasp/loop gaps
    return result

def get_clean(idx: int) -> Image.Image:
    if idx not in st.session_state.clean:
        with st.spinner(f"Removing background for image {idx+1}…"):
            st.session_state.clean[idx] = remove_bg(st.session_state.raw[idx])
    return st.session_state.clean[idx]

# ── Font loader ───────────────────────────────────────────────────────────────
def get_font(size: int, bold: bool = False) -> ImageFont.FreeTypeFont:
    paths = {
        True:  ["C:/Windows/Fonts/arialbd.ttf","C:/Windows/Fonts/calibrib.ttf","C:/Windows/Fonts/verdanab.ttf"],
        False: ["C:/Windows/Fonts/arial.ttf",  "C:/Windows/Fonts/calibri.ttf", "C:/Windows/Fonts/verdana.ttf"],
    }
    for p in paths[bold]:
        try: return ImageFont.truetype(p, size)
        except: pass
    return ImageFont.load_default()

# ── Find best corner for details box ─────────────────────────────────────────
def find_best_corner(canvas_arr: np.ndarray, bg_color: tuple) -> tuple:
    """Return (x, y) of corner with most background pixels."""
# ── Build final image — resolution matches input, table appended below ────────
def build_final_image(jewelry_rgba: Image.Image, ann: dict, gold_type: str,
                      bg_mode: str = "gold", custom_bg: str = "#FFFFFF",
                      x_pct: int = 0, y_pct: int = 0,
                      angle_images: list = None,
                      company: str = "wondr") -> Image.Image:
    # ── Company theme ─────────────────────────────────────────────────────────
    _co_cfg   = COMPANY_CFG.get(company, COMPANY_CFG["wondr"])
    if _co_cfg["logo_uri"] is None:
        _co_cfg["logo_uri"] = _get_vd_logo_uri()

    # ── Background colour resolution ─────────────────────────────────────────
    if bg_mode == "transparent":
        bg_color = (255, 255, 255)   # placeholder; jewel zone will be fully transparent
    elif bg_mode == "custom":
        _h = custom_bg.lstrip("#")
        bg_color = tuple(int(_h[i:i+2], 16) for i in (0, 2, 4))
    else:
        bg_color = get_bg_color(gold_type)

    GOLD     = _co_cfg["accent"]
    CREAM    = _co_cfg["value_c"]
    LABEL_C  = _co_cfg["label_c"]
    NAVY     = _co_cfg["table_bg"]
    WHITE    = (255, 255, 255)
    # Divider: white on dark bg, black on light bg
    _bg_lum  = (bg_color[0] * 299 + bg_color[1] * 587 + bg_color[2] * 114) / 1000
    DIVIDER  = (255, 255, 255) if _bg_lum < 128 else (0, 0, 0)
    # Company can override divider/border color
    if _co_cfg["border_c"] is not None:
        DIVIDER = _co_cfg["border_c"]

    # ── Dynamic canvas — use original image resolution ────────────────────────
    jw, jh     = jewelry_rgba.size
    CANVAS_W   = max(jw, jh)
    PAD        = max(int(CANVAS_W * PAD_RATIO), 20)
    TABLE_H    = max(int(CANVAS_W * TABLE_H_RATIO), 150)
    JEWELRY_H  = CANVAS_W

    # ── 1. Jewelry zone ───────────────────────────────────────────────────────
    # Pre-compute angle column dimensions so we can position jewelry correctly
    _angs_all = [a for a in (angle_images or []) if a is not None][:3]
    _has_ang  = bool(_angs_all)
    ANG_COL_W = int(CANVAS_W * 0.32) if _has_ang else 0   # right 32% for angle col
    DIV_W     = max(2, int(CANVAS_W * 0.003)) if _has_ang else 0  # gold divider
    MAIN_W    = CANVAS_W - ANG_COL_W - DIV_W               # left area for main jewel

    if bg_mode == "transparent":
        jewel_zone = Image.new("RGBA", (CANVAS_W, JEWELRY_H), (0, 0, 0, 0))
    else:
        jewel_zone = Image.new("RGBA", (CANVAS_W, JEWELRY_H), (*bg_color, 255))

    # Scale & paste main jewelry within its (possibly narrower) left column
    max_w   = MAIN_W - 2 * PAD
    max_h   = JEWELRY_H - 2 * PAD
    scale   = min(max_w / jw, max_h / jh)
    nw, nh  = int(jw * scale), int(jh * scale)
    resized = jewelry_rgba.resize((nw, nh), Image.LANCZOS)

    # Centre within left column + user offset
    x_off = (MAIN_W - nw) // 2 + int(MAIN_W * x_pct / 100)
    y_off = (JEWELRY_H - nh) // 2 + int(JEWELRY_H * y_pct / 100)
    x_off = max(0, min(MAIN_W - nw, x_off))
    y_off = max(0, min(JEWELRY_H - nh, y_off))
    jewel_zone.paste(resized, (x_off, y_off), mask=resized.split()[3])

    # ── Angle column: stacked vertically on the RIGHT side of jewel_zone ─────
    if _has_ang:
        n_ang  = len(_angs_all)
        _slot_h = JEWELRY_H // n_ang
        _dz     = ImageDraw.Draw(jewel_zone)
        # Vertical divider between main area and angle column
        _dz.rectangle([(MAIN_W, 0), (MAIN_W + DIV_W, JEWELRY_H)],
                      fill=(*DIVIDER, 255))
        for _ai, _ang in enumerate(_angs_all):
            _aw, _ah  = _ang.size
            _max_aw   = ANG_COL_W - 2 * PAD
            _max_ah   = _slot_h - 2 * PAD
            _scale_a  = min(_max_aw / max(_aw, 1), _max_ah / max(_ah, 1))
            _naw      = max(1, int(_aw * _scale_a))
            _nah      = max(1, int(_ah * _scale_a))
            _ang_res  = _ang.resize((_naw, _nah), Image.LANCZOS)
            _ax       = MAIN_W + DIV_W + (ANG_COL_W - _naw) // 2
            _ay       = _ai * _slot_h + (_slot_h - _nah) // 2
            jewel_zone.paste(_ang_res, (_ax, _ay), mask=_ang_res.split()[3])
            # Horizontal divider between angle slots
            if _ai > 0:
                _dz.rectangle(
                    [(MAIN_W + DIV_W, _ai * _slot_h),
                     (CANVAS_W,       _ai * _slot_h + max(1, int(CANVAS_W * 0.001)))],
                    fill=(*DIVIDER, 255))

    # For transparent mode return just the RGBA jewel (no table, ideal for web)
    if bg_mode == "transparent":
        try:
            import io as _io, base64 as _b64
            _logo_data = _co_cfg["logo_uri"].split(',')[1]
            _logo_img  = Image.open(_io.BytesIO(_b64.b64decode(_logo_data))).convert("RGBA")
            _logo_box  = max(int(CANVAS_W * 0.14), 80)
            _lw, _lh   = _logo_img.size
            _scale_l   = min(_logo_box / max(_lw, 1), _logo_box / max(_lh, 1))
            _logo_img  = _logo_img.resize(
                (max(1, int(_lw * _scale_l)), max(1, int(_lh * _scale_l))), Image.LANCZOS)
            _margin    = max(int(CANVAS_W * 0.015), 10)
            _lx = CANVAS_W - _logo_img.width - _margin
            _ly = JEWELRY_H - _logo_img.height - _margin
            _logo_rgba = _logo_img.copy()
            _lr, _lg, _lb, _la = _logo_rgba.split()
            _la = _la.point(lambda x: int(x * 0.70))
            _logo_rgba.putalpha(_la)
            jewel_zone.paste(_logo_rgba, (_lx, _ly), _logo_rgba)
        except Exception:
            pass
        # Angles are already embedded in jewel_zone as a right-side column
        return jewel_zone   # RGBA — caller must save as PNG


    # ── Logo watermark: bottom-right of jewelry zone ─────────────────────────
    try:
        import io as _io, base64 as _b64
        _logo_data = _co_cfg["logo_uri"].split(',')[1]
        _logo_img  = Image.open(_io.BytesIO(_b64.b64decode(_logo_data))).convert("RGBA")
        # Keep aspect ratio — fit inside a box of ~14% canvas width
        _logo_box  = max(int(CANVAS_W * 0.14), 80)
        _lw, _lh   = _logo_img.size
        _scale_l   = min(_logo_box / max(_lw, 1), _logo_box / max(_lh, 1))
        _logo_img  = _logo_img.resize(
            (max(1, int(_lw * _scale_l)), max(1, int(_lh * _scale_l))), Image.LANCZOS)
        _margin    = max(int(CANVAS_W * 0.015), 10)
        _lx        = CANVAS_W - _logo_img.width - _margin
        _ly        = JEWELRY_H - _logo_img.height - _margin
        # Paste at 70% opacity
        _logo_rgba = _logo_img.copy()
        _lr, _lg, _lb, _la = _logo_rgba.split()
        _la = _la.point(lambda x: int(x * 0.70))
        _logo_rgba.putalpha(_la)
        jewel_zone.paste(_logo_rgba, (_lx, _ly), _logo_rgba)
    except Exception:
        pass
    # ── 2. Details table: CANVAS_W x TABLE_H ─────────────────────────────────
    # Font sizes scale with canvas width to stay sharp at any resolution
    fs = max(int(CANVAS_W * 0.013), 10)   # base font scale unit
    table = Image.new("RGB", (CANVAS_W, TABLE_H), NAVY)
    draw  = ImageDraw.Draw(table)

    # Gold top border
    bdr = max(int(CANVAS_W * 0.005), 4)
    draw.rectangle([(0, 0), (CANVAS_W, bdr)], fill=GOLD)

    # Fonts — all scale with canvas
    hf = get_font(int(fs * 1.8), bold=True)   # brand header
    lf = get_font(int(fs * 1.3), bold=True)   # column label
    vf = get_font(int(fs * 1.9), bold=True)   # column value
    nf = get_font(int(fs * 1.4), bold=False)  # notes

    # Brand header bar
    mg = max(int(CANVAS_W * 0.018), 12)   # margin
    ty = mg
    draw.text((mg, ty), _co_cfg["brand_line"], fill=(20, 20, 20), font=hf)
    draw.text((CANVAS_W - int(CANVAS_W*0.20), ty), _co_cfg["website"], fill=GOLD, font=lf)
    ty += int(fs * 2.8)
    draw.line([(0, ty), (CANVAS_W, ty)], fill=DIVIDER, width=max(2, int(CANVAS_W*0.002)))
    ty += mg

    # ── Row 1: Design Code | Gold Type | Gold Wt ─────────────────────────────
    col_w = CANVAS_W // 3   # ~213px each
    cols_r1 = [
        ("DESIGN CODE", ann.get("design_code") or "—"),
        ("GOLD TYPE",   ann.get("gold_type")   or "—"),
        ("GOLD WEIGHT", f"{float(ann['gold_weight']):.3f} g" if ann.get("gold_weight") else "—"),
    ]
    for i, (lbl, val) in enumerate(cols_r1):
        cx = i * col_w + mg
        draw.text((cx, ty),            lbl, fill=LABEL_C, font=lf)
        draw.text((cx, ty + int(fs*1.6)), val, fill=CREAM,   font=vf)
        if i < 2:
            dv_h = int(fs * 4.2)
            draw.line([(col_w*(i+1), ty-4), (col_w*(i+1), ty+dv_h)], fill=DIVIDER, width=max(2,int(CANVAS_W*0.001)))

    ty += int(fs * 4.5)
    draw.line([(0, ty), (CANVAS_W, ty)], fill=DIVIDER, width=max(2, int(CANVAS_W*0.002)))
    ty += mg

    # ── Row 2: Dia Stones | Diamond CT | Gem Stones | Gem Stone CT ───────────
    col_w2 = CANVAS_W // 4   # 160px each
    dia_stones = ann.get("diamond_stones") or "—"
    gem_stones = ann.get("gem_stones")     or "—"
    cols_r2 = [
        ("DIA. STONES",    str(int(float(dia_stones))) if dia_stones != "—" else "—"),
        ("DIAMOND (CT)",   f"{float(ann['diamond_carat']):.3f}" if ann.get("diamond_carat") else "—"),
        ("GEM STONES",     str(int(float(gem_stones))) if gem_stones != "—" else "—"),
        ("GEM STONE (CT)", f"{float(ann['gem_stone']):.3f}"     if ann.get("gem_stone")     else "—"),
    ]
    for i, (lbl, val) in enumerate(cols_r2):
        cx = i * col_w2 + mg
        draw.text((cx, ty),            lbl, fill=LABEL_C, font=lf)
        draw.text((cx, ty + int(fs*1.6)), val, fill=CREAM,   font=vf)
        if i < 3:
            dv_h = int(fs * 4.2)
            draw.line([(col_w2*(i+1), ty-4), (col_w2*(i+1), ty+dv_h)], fill=DIVIDER, width=max(2,int(CANVAS_W*0.001)))

    ty += int(fs * 4.5)
    draw.line([(0, ty), (CANVAS_W, ty)], fill=DIVIDER, width=max(2, int(CANVAS_W*0.002)))
    ty += int(mg * 0.8)

    # ── Row 3: Notes (if any) ─────────────────────────────────────────────────
    if ann.get("description"):
        draw.text((mg, ty), "NOTES:", fill=LABEL_C, font=lf)
        draw.text((mg + int(CANVAS_W*0.09), ty), str(ann["description"])[:80], fill=(60, 60, 60), font=nf)

    # Gold bottom border
    draw.rectangle([(0, TABLE_H - bdr), (CANVAS_W, TABLE_H)], fill=GOLD)

    # ── 3. Combine: jewelry zone (angles already in right column) + table ───────
    TOTAL_H = JEWELRY_H + TABLE_H
    final   = Image.new("RGB", (CANVAS_W, TOTAL_H), (255, 255, 255))
    final.paste(jewel_zone.convert("RGB"), (0, 0))
    final.paste(table, (0, JEWELRY_H))

    return final


def make_zip(paths: list, anns: dict | None = None) -> bytes:
    buf = io.BytesIO()
    with zipfile.ZipFile(buf, "w", zipfile.ZIP_DEFLATED) as zf:
        for p in paths:
            if Path(p).exists(): zf.write(p, Path(p).name)
        ann_path = OUTPUT_DIR / "annotations.json"
        if ann_path.exists(): zf.write(ann_path, "annotations.json")

        # ── Excel catalogue ───────────────────────────────────────────────────
        if anns:
            try:
                import openpyxl
                from openpyxl.styles import Font, PatternFill, Alignment
                wb = openpyxl.Workbook()
                ws = wb.active
                ws.title = "Jewellery Catalogue"
                headers = ["File", "Design Code", "Gold Type", "Gold Wt (g)",
                           "Diamond (CT)", "Diamond Stones",
                           "Gem Stone (CT)", "Gem Stones", "Notes"]
                gold_fill = PatternFill("solid", fgColor="AB8732")
                hdr_font  = Font(bold=True, color="FFFFFF", size=11)
                for ci, h in enumerate(headers, 1):
                    cell = ws.cell(row=1, column=ci, value=h)
                    cell.fill = gold_fill
                    cell.font = hdr_font
                    cell.alignment = Alignment(horizontal="center")
                for ri, (fn, ann) in enumerate(anns.items(), 2):
                    ws.cell(ri, 1, fn)
                    ws.cell(ri, 2, ann.get("design_code", ""))
                    ws.cell(ri, 3, ann.get("gold_type", ""))
                    ws.cell(ri, 4, float(ann.get("gold_weight")    or 0))
                    ws.cell(ri, 5, float(ann.get("diamond_carat")  or 0))
                    ws.cell(ri, 6,   int(float(ann.get("diamond_stones") or 0)))
                    ws.cell(ri, 7, float(ann.get("gem_stone")      or 0))
                    ws.cell(ri, 8,   int(float(ann.get("gem_stones")     or 0)))
                    ws.cell(ri, 9, ann.get("description", ""))
                for col in ws.columns:
                    ws.column_dimensions[col[0].column_letter].width = 18
                xl_buf = io.BytesIO()
                wb.save(xl_buf)
                zf.writestr("jewellery_catalogue.xlsx", xl_buf.getvalue())
            except Exception:
                pass
    return buf.getvalue()


